            continue
        if ln.endswith(':'):
            continue
        if re.search('[A-Za-z]', ln):
            cleaned = ln.lstrip('-–— ').rstrip(' -–—')
            if len(cleaned) < 3:
                continue
            projects.append(cleaned)
    seen = set(); out = []
    for p in projects:
        if p not in seen:
            seen.add(p); out.append(p)
    return out

